const items = $input.all();
const list = items.flatMap((i) => {
  const j = i.json;
  if (Array.isArray(j)) return j;
  if (j && Array.isArray(j.data)) return j.data;
  return j && typeof j === 'object' ? [j] : [];
});
const sanmar = list.find((s) => s && s.slug === 'sanmar');
if (!sanmar) {
  throw new Error(`SanMar supplier not found. Saw ${list.length} suppliers.`);
}
return [{ json: { sid: sanmar.id, name: sanmar.name } }];

const limitRaw = $env.SANMAR_PRODUCT_LIMIT;
const limit = limitRaw ? parseInt(limitRaw, 10) : 0;
if (!Number.isFinite(limit) || limit <= 0) return $input.all();
return $input.all().slice(0, limit);

// SanMar FTP (EPDD/SDL) CSV row -> API-HUB ProductIngest
// Note: SanMar's FTP feeds often provide image *file names* (not URLs). We only pass URLs if present.
const rows = $input.all();

function pick(obj, keys) {
  for (const k of keys) {
    if (obj[k] !== undefined && obj[k] !== null && String(obj[k]).trim() !== '') return obj[k];
  }
  return null;
}

return rows.map((item) => {
  const p = item.json ?? {};

  const supplierSku = String(pick(p, ['STYLE#', 'STYLE', 'style', 'Style', 'STYLE_NO', 'STYLE_NO#']) ?? '');
  const productName = pick(p, ['PRODUCT_TITLE', 'PRODUCT_NAME', 'product_name', 'TITLE', 'NAME']) ?? 'Unnamed SanMar Product';
  const brand = pick(p, ['MILL', 'BRAND_NAME', 'BRAND', 'brand']) ?? 'SanMar';
  const description = pick(p, ['PRODUCT_DESCRIPTION', 'description', 'DESC']) ?? null;

  const categoryName = pick(p, ['CATEGORY_NAME', 'CATEGORY', 'Main Category']) ?? null;
  const subCategoryName = pick(p, ['SUBCATEGORY_NAME', 'SUBCATEGORY', 'Sub Category']) ?? null;

  const partId = String(pick(p, ['SKU', 'UNIQUE_KEY', 'INVENTORY_KEY', 'PART_ID', 'part_id']) ?? '');
  const basePriceRaw = pick(p, ['PIECE_PRICE', 'PRICE', 'BASE_PRICE', 'COST']) ?? 0;
  const inventoryRaw = pick(p, ['QTY', 'QTY_AVAILABLE', 'INVENTORY', 'INVENTORY_QTY', 'AVAILABLE_QTY']) ?? 0;

  const frontUrl = pick(p, ['FRONT_MODEL_IMAGE_URL', 'FRONT_MODEL_URL', 'FRONT_IMAGE_URL']) ?? null;
  const backUrl = pick(p, ['BACK_MODEL_IMAGE_URL', 'BACK_MODEL_URL', 'BACK_IMAGE_URL']) ?? null;
  const imageUrl = pick(p, ['PRODUCT_IMAGE_URL', 'PRODUCT_IMAGE', 'IMAGE_URL']) ?? frontUrl;

  const images = [
    { url: frontUrl, image_type: 'front', sort_order: 0 },
    { url: backUrl, image_type: 'back', sort_order: 1 },
  ].filter((img) => img.url);

  return {
    json: {
      supplier_sku: supplierSku,
      product_name: productName,
      brand,
      description,
      product_type: 'apparel',
      image_url: imageUrl,
      ops_product_id: pick(p, ['STYLE_INDEX', 'OPS_PRODUCT_ID', 'ops_product_id']) ? String(pick(p, ['STYLE_INDEX', 'OPS_PRODUCT_ID', 'ops_product_id'])) : null,
      category_name: subCategoryName ? `${categoryName ?? 'Uncategorized'} / ${subCategoryName}` : categoryName,
      variants: [
        {
          part_id: partId,
          color: pick(p, ['COLOR_NAME', 'COLOR', 'color']) ?? null,
          size: pick(p, ['SIZE', 'SIZE_NAME', 'size']) ?? null,
          sku: partId,
          base_price: Number(basePriceRaw) || 0,
          inventory: parseInt(String(inventoryRaw), 10) || 0,
          warehouse: pick(p, ['WAREHOUSE', 'WHSE', 'WHSE_NO']) ? String(pick(p, ['WAREHOUSE', 'WHSE', 'WHSE_NO'])) : 'SanMar',
        }
      ],
      images,
      options: []
    }
  };
});
